class Solution {
public:
    int getMinSwaps(string num, int k) {
        string res = num;
        for (int i = 0; i < k; i++) {
            next_permutation(res.begin(), res.end());
            while (res <= num) {
                next_permutation(res.begin(), res.end());
            }
        }
        int ans = 0;
        for (int i = 0; i < num.size(); i++) {
            if (num[i] != res[i]) {
                for (int j = i + 1; j < num.size(); j++) {
                    if (num[j] == res[i]) {
                        for (int x = j; x > i; x--) {
                            swap(num[x], num[x - 1]);
                            ans++;
                        }
                        break;
                    }
                }
            }
        }
        return ans;
    }
};

